    ```java
import java.util.*;

class MovieRentingSystem {
    private Map<Integer, Map<Integer, Integer>> price;
    private TreeSet<int[]> rented;
    private List<TreeSet<int[]>> available;

    public MovieRentingSystem(int n, int[][] entries) {
        price = new HashMap<>();
        rented = new TreeSet<>((a, b) -> a[0] == b[0] ? a[1] - b[1] : a[0] - b[0]);
        available = new ArrayList<>(10000);
        for (int i = 0; i < 10000; i++) {
            available.add(new TreeSet<>((a, b) -> a[0] == b[0] ? a[1] - b[1] : a[0] - b[0]));
        }

        for (int[] entry : entries) {
            int shop = entry[0], movie = entry[1], p = entry[2];
            price.computeIfAbsent(shop, x -> new HashMap<>()).put(movie, p);
            available.get(movie).add(new int[]{p, shop});
        }
    }

    public List<Integer> search(int movie) {
        List<Integer> result = new ArrayList<>();
        Iterator<int[]> iterator = available.get(movie).iterator();
        for (int i = 0; i < 5 && iterator.hasNext(); i++) {
            result.add(iterator.next()[1]);
        }
        return result;
    }

    public void rent(int shop, int movie) {
        int p = price.get(shop).get(movie);
        rented.add(new int[]{p, shop});
        available.get(movie).remove(new int[]{p, shop});
    }

    public void drop(int shop, int movie) {
        int p = price.get(shop).get(movie);
        rented.remove(new int[]{p, shop});
        available.get(movie).add(new int[]{p, shop});
    }

    public List<List<Integer>> report() {
        List<List<Integer>> result = new ArrayList<>();
        Iterator<int[]> iterator = rented.iterator();
        for (int i = 0; i < 5 && iterator.hasNext(); i++) {
            int[] pair = iterator.next();
            result.add(Arrays.asList(pair[1], pair[0]));
        }
        return result;
    }
}
```


